type QuoteStep = { op: "quote"; items: Item[] };
type Input = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

export const run = (input: Input): { results: unknown[] } => {
  const results = input.steps.map((step) => {
    const itemsTotal = step.items.reduce((sum, _item) => sum + 110, 0);
    return { premium: itemsTotal + PROCESSING_FEE };
  });
  return { results };
};

