const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Input = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
type QuoteResult = { premium: number };

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const basePremiumForType = (type: string, count: number): number => {
  const unit = BASE_PREMIUM[type];
  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
    return BLOCK_BASE_PREMIUM;
  }
  return unit * count;
};

const basePremium = (items: Item[]): number => {
  let total = 0;
  for (const [type, count] of countByType(items)) {
    total += basePremiumForType(type, count);
  }
  return total;
};

// MHPCO always rounds premiums in its own favor (up).
const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);

const quotePremium = (step: QuoteStep): QuoteResult => {
  const base = basePremium(step.items);
  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
  return {
    premium: roundUpInMHPCOFavor(base + firstInsuranceSurcharge + PROCESSING_FEE),
  };
};

export const run = (input: Input): { results: QuoteResult[] } => ({
  results: input.steps.map(quotePremium),
});

