// --- Rates, fees, and thresholds ---
const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const LOYALTY_RATE = 0.2;
const LOYALTY_THRESHOLD_YEARS = 2;
const CURSE_RATE = 0.5;
const HIGH_ENCHANTMENT_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;

// --- Item catalog ---
const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

// --- Domain types ---
type Customer = { yearsWithMHPCO: number };
type Item = { type: string; cursed?: boolean; enchantment?: number };
type QuoteStep = { op: "quote"; items: Item[] };
type Input = { customer: Customer; steps: QuoteStep[] };
type QuoteResult = { premium: number };

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const basePremiumForType = (type: string, count: number): number => {
  const unit = BASE_PREMIUM[type];
  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
    return BLOCK_BASE_PREMIUM;
  }
  return unit * count;
};

const basePremium = (items: Item[]): number =>
  Array.from(countByType(items)).reduce(
    (total, [type, count]) => total + basePremiumForType(type, count),
    0,
  );

// MHPCO always rounds premiums in its own favor (up).
const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);

const isCursed = (item: Item): boolean => item.cursed === true;
const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const itemSurcharge = (item: Item): number => {
  const unit = BASE_PREMIUM[item.type];
  const curseSurcharge = isCursed(item) ? unit * CURSE_RATE : 0;
  const enchantmentSurcharge = isHighlyEnchanted(item)
    ? unit * HIGH_ENCHANTMENT_RATE
    : 0;
  return curseSurcharge + enchantmentSurcharge;
};

const sumItemSurcharges = (items: Item[]): number =>
  items.reduce((total, item) => total + itemSurcharge(item), 0);

const isLoyalCustomer = (customer: Customer): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;

const loyaltyDiscount = (base: number, customer: Customer): number =>
  isLoyalCustomer(customer) ? base * LOYALTY_RATE : 0;

const firstInsuranceSurcharge = (base: number): number =>
  base * FIRST_INSURANCE_RATE;

const quotePremium = (step: QuoteStep, customer: Customer): QuoteResult => {
  const base = basePremium(step.items);
  const itemSurcharges = sumItemSurcharges(step.items);
  const premium =
    base +
    itemSurcharges +
    firstInsuranceSurcharge(base) -
    loyaltyDiscount(base, customer) +
    PROCESSING_FEE;
  return { premium: roundUpInMHPCOFavor(premium) };
};

export const run = (input: Input): { results: QuoteResult[] } => ({
  results: input.steps.map((step) => quotePremium(step, input.customer)),
});

import { describe, it, expect } from "vitest";
import { run } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Simplest case
  it("empty item list — premium 5 G (only processing fee)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });

  // Base premiums for single items (with processing fee)
  it("single sword (first insurance) — premium 115 G (100 base + 10 first + 5 fee)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("single amulet (first insurance) — premium 71 G (60 base + 6 first + 5 fee)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("single staff (first insurance) — premium 93 G (80 base + 8 first + 5 fee)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 93 });
  });
  it("single potion (first insurance) — premium 49 G (40 base + 4 first + 5 fee)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 49 });
  });

  // Components
  it("single rune (first insurance) — premium 33 G (25 base + 2.5 first + 5 fee = 32.5 → 33)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 33 });
  });
  it("single moonstone (first insurance) — premium 33 G (same as rune)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "moonstone" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 33 });
  });

  // Building block of 3 alike components
  it("2 runes — premium 60 G (50 base + 5 first + 5 fee, no block)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 60 });
  });
  it("3 runes — premium 71 G (60 block + 6 first + 5 fee, block applies)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("4 runes — premium 115 G (100 base + 10 first + 5 fee, no block, requires exactly 3)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("7 runes — premium 198 G (175 base + 17.5 first + 5 fee = 197.5 → 198)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 198 });
  });

  // Alike components — different types are not alike
  it("2 runes + 1 moonstone — premium 88 G (75 base + 7.5 first + 5 fee = 87.5 → 88, different types not alike)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 88 });
  });
  it("3 runes + 3 moonstones — premium 137 G (120 base from 2 blocks + 12 first + 5 fee)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" }, { type: "rune" }, { type: "rune" },
            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 137 });
  });

  // Item-specific modifiers
  it("cursed sword (first insurance) — premium 165 G (100 base + 50 curse + 10 first + 5 fee)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
    });
    expect(result.results[0]).toEqual({ premium: 165 });
  });
  it("sword ench 5 (first insurance) — premium 145 G (100 base + 30 high-ench + 10 first + 5 fee)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }],
    });
    expect(result.results[0]).toEqual({ premium: 145 });
  });
  it("sword ench 4 — premium 115 G (no high-ench surcharge)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("cursed sword ench 5 — premium 195 G (100 + 50 curse + 30 high + 10 first + 5 fee)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true, enchantment: 5 }] }],
    });
    expect(result.results[0]).toEqual({ premium: 195 });
  });

  // Customer-level modifiers
  it("customer with 2 years, single sword — premium 95 G (loyalty discount applies)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 2 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 95 });
  });
  it.todo("customer with 1 year — no loyalty discount");
  it.todo("first contract — 10% first insurance surcharge applies");
  it.todo("second contract — 15% follow-up discount applies");

  // Modifier scope on multi-item policies
  it.todo("cursed sword + plain amulet — base 160 G, +50 curse = 210 G + fee = 215 G");

  // Rounding in MHPCO's favor
  it.todo("premium yielding 197.5 G — rounded up to 198 G");
  it.todo("payout yielding 350.5 G — rounded down to 350 G");

  // Integration examples
  it.todo("newcomer cursed sword — premium 165 G");
  it.todo("long-standing customer's second contract with cursed sword ench 7 — premium 160 G");

  // Claims — basic deductible
  it.todo("regular sword damage 500 G — payout 400 G (deductible)");
  it.todo("rune damage 200 G — payout 100 G (deductible, no special clause)");

  // Claims — enchantment threshold
  it.todo("dragon-material sword ench 8, damage 1000 G — payout 400 G (50% then deductible)");
  it.todo("dragon-material sword ench 9, damage 1000 G — payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword ench 5, damage 800 G — payout 700 G (dragon full, then deductible)");
  it.todo("steel sword ench 9, damage 1000 G — payout 400 G (50% then deductible)");

  // Claims — multiple damages
  it.todo("dragon attack damages sword 500 + amulet 300 — payout 600 G (deductible per item)");

  // Multiple items of the same type
  it.todo("two swords policy — insurance sum 2000 G, cap 4000 G");
